module RefModule (
    input wire [4:0] data_in,
    input wire ack,
    input wire clk,
    output reg [4:0] data_out
);
    reg [4:0] last_data;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (ack) begin
            data_out <= data_in;
            last_data <= data_in;
        end else begin
            data_out <= last_data;
        end
    end
endmodule
